  ('dietitian-moex-00013', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據國民飲食指標以及世界衛生組織對嬰兒哺乳的建議，下列敘述何者最正確？', '["母乳應至少哺餵6個月，只要媽媽及小孩想要即可持續", "6個月內的嬰兒，除了母乳，僅能喝水，不可吃其他食物", "6個月內不便哺餵母乳的嬰兒應該給與配方奶、鮮奶或羊奶", "母親哺乳時，若還在坐月子期間，不可喝水"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00014', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據營養師法，非領有營養師證書，而自稱營養師者，依規定之處罰為何？', '["1萬元以上5萬元以下罰鍰", "2萬元以上10萬元以下罰鍰", "3萬元以上15萬元以下罰鍰", "4萬元以上20萬元以下罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
